class ErrorBoundary extends React.Component<
  { fallback?: React.ReactNode },
  { hasError: boolean }
> {
  constructor(props) {
    super(props);
    this.state = { hasError: false };
  }

  // 🔹 Обновляем state, чтобы показать fallback при ошибке
  static getDerivedStateFromError(error: Error) {
    return { hasError: true };
  }

  // 🔹 Здесь можно логировать ошибку (в консоль, Sentry, GlitchTip и т.п.)
  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error("Ошибка в компоненте:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      // 🔹 Показываем запасной UI
      return this.props.fallback ?? <h2>Что-то пошло не так 😞</h2>;
    }

    // 🔹 Если ошибки нет — рендерим детей
    return this.props.children;
  }
}

export default ErrorBoundary;
