import { z } from "zod";

const schema = z.object({
  email: z.string().email("Введите корректный email"),
  password: z.string().min(8, "Минимум 8 символов"),
});

type Values = z.infer<typeof schema>;
type Errors = Partial<Record<keyof Values, string>>;

export function LoginForm() {
  const [values, setValues] = useState<Values>({ email: "", password: "" });
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [errors, setErrors] = useState<Errors>({});
  const [formError, setFormError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const firstErrorRef = useRef<HTMLInputElement | null>(null);

  const validate = (v: Values): Errors => {
    const res = schema.safeParse(v);
    if (res.success) return {};
    const e: Errors = {};
    res.error.issues.forEach(i => {
      const path = i.path[0] as keyof Values;
      e[path] = i.message;
    });
    return e;
  };

  // валидация при изменении уже тронутых полей
  useEffect(() => {
    const e = validate(values);
    setErrors(e);
  }, [values]);

  const onChange = (name: keyof Values) => (e: React.ChangeEvent<HTMLInputElement>) => {
    setValues(v => ({ ...v, [name]: e.target.value }));
  };
  const onBlur = (name: keyof Values) => () => setTouched(t => ({ ...t, [name]: true }));

  const onSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setTouched({ email: true, password: true });
    const eMap = validate(values);
    setErrors(eMap);
    setFormError(null);

    if (Object.keys(eMap).length) {
      // фокус на первом ошибочном
      const firstField = document.querySelector<HTMLInputElement>('[aria-invalid="true"]');
      firstField?.focus();
      return;
    }

    try {
      setLoading(true);
      // имитация запроса
      const ok = await fakeLogin(values);
      if (!ok) {
        // серверная ошибка к полю или общая
        setErrors(prev => ({ ...prev, email: "Email уже зарегистрирован" }));
      }
    } catch (err) {
      setFormError("Не удалось отправить форму. Попробуйте позже.");
    } finally {
      setLoading(false);
    }
  };

  const emailInvalid = !!errors.email && touched.email;
  const passInvalid = !!errors.password && touched.password;

  return (
    <form onSubmit={onSubmit} noValidate>
      {formError && (
        <div role="alert" className="mb-3 text-red-600">
          {formError}
        </div>
      )}

      <label>
        Email
        <input
          type="email"
          value={values.email}
          onChange={onChange("email")}
          onBlur={onBlur("email")}
          aria-invalid={emailInvalid || undefined}
          aria-describedby={emailInvalid ? "email-error" : undefined}
        />
      </label>
      {emailInvalid && (
        <div id="email-error" role="alert" className="text-red-600 text-sm">
          {errors.email}
        </div>
      )}

      <label>
        Пароль
        <input
          type="password"
          value={values.password}
          onChange={onChange("password")}
          onBlur={onBlur("password")}
          aria-invalid={passInvalid || undefined}
          aria-describedby={passInvalid ? "password-error" : undefined}
        />
      </label>
      {passInvalid && (
        <div id="password-error" role="alert" className="text-red-600 text-sm">
          {errors.password}
        </div>
      )}

      <button type="submit" disabled={loading}>
        {loading ? "Отправка..." : "Войти"}
      </button>
    </form>
  );
}

async function fakeLogin(_: { email: string; password: string }) {
  await new Promise(r => setTimeout(r, 600));
  return false; // вернём “email занят”
}
