import { z } from "zod";
import { zodResolver } from "@hookform/resolvers/zod";

const schema = z.object({
  email: z.string().email("Введите корректный email"),
  password: z.string().min(8, "Минимум 8 символов"),
});
type FormData = z.infer<typeof schema>;

export function RHFLoginForm() {
  const { register, handleSubmit, formState, setError } = useForm<FormData>({
    resolver: zodResolver(schema),
    mode: "onBlur", // blur + onSubmit
  });
  const { errors, isSubmitting } = formState;

  const onSubmit = async (data: FormData) => {
    try {
      const ok = await fakeLogin(data);
      if (!ok) {
        // серверная ошибка к конкретному полю
        setError("email", { type: "server", message: "Email уже зарегистрирован" });
      }
    } catch {
      // общая ошибка формы
      setError("root", { type: "server", message: "Сервис недоступен. Попробуйте позже." });
    }
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} noValidate>
      {errors.root && (
        <div role="alert" className="mb-3 text-red-600">
          {errors.root.message}
        </div>
      )}

      <label>
        Email
        <input
          type="email"
          {...register("email")}
          aria-invalid={!!errors.email || undefined}
          aria-describedby={errors.email ? "email-error" : undefined}
        />
      </label>
      {errors.email && (
        <div id="email-error" role="alert" className="text-red-600 text-sm">
          {errors.email.message}
        </div>
      )}

      <label>
        Пароль
        <input
          type="password"
          {...register("password")}
          aria-invalid={!!errors.password || undefined}
          aria-describedby={errors.password ? "password-error" : undefined}
        />
      </label>
      {errors.password && (
        <div id="password-error" role="alert" className="text-red-600 text-sm">
          {errors.password.message}
        </div>
      )}

      <button type="submit" disabled={isSubmitting}>
        {isSubmitting ? "Отправка..." : "Войти"}
      </button>
    </form>
  );
}
